    that.model.get('style').views[style_view].then(function(view) {
        view.style();
    });
});
this.obj.on('movestart', function (e) {
    var style_view = Object.keys(that.model.get('style').views)[0];
    that.model.get('style').views[style_view].then(function(view) {
